-- Auto-generated SQL Script using country-state-city real data for Pakistan

-- Create Provinces Table
CREATE TABLE IF NOT EXISTS public.provinces (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL UNIQUE,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Create Cities Table
CREATE TABLE IF NOT EXISTS public.cities (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  province_id UUID REFERENCES public.provinces(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  is_serviceable BOOLEAN DEFAULT true,
  created_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE(province_id, name)
);

-- Enable RLS and grant read access to all users
ALTER TABLE public.provinces ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.cities ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Allow public read on provinces" ON public.provinces FOR SELECT USING (true);
CREATE POLICY "Allow public read on cities" ON public.cities FOR SELECT USING (true);
GRANT SELECT ON public.provinces TO anon, authenticated;
GRANT SELECT ON public.cities TO anon, authenticated;
GRANT ALL ON public.provinces TO service_role;
GRANT ALL ON public.cities TO service_role;

